#include<bits/stdc++.h>
using namespace std;
long double f;
int a,b,c,d;
int main(void){
	cin>>a>>b>>c>>d;
	f=(((a+b+(c*1.0/2))*1.0)/((a+b+c+d)*1.0))*(1e7);
	if(f>=9.9*1e6)cout<<"EX+";
	else if(f>=9.8*1e6)cout<<"EX";
	else if(f>=9.5*1e6)cout<<"AA";
	else if(f>=9.2*1e6)cout<<"A";
	else if(f>=8.9*1e6)cout<<"B";
	else if(f>=8.6*1e6)cout<<"C";
	else cout<<"D";
	return false;
}
